// Campanha Perdão de Dívida — filtra elegíveis e calcula próxima fase
// Aquecimento: AJUSTE o LIMITE_DIA conforme o dia da campanha (50 -> 100 -> 150)
const LIMITE_DIA = 50;

const hoje = new Date();
hoje.setHours(0, 0, 0, 0);

const elegiveis = [];
const logs = [];

for (const item of $input.all()) {
  const row = item.json;

  // Blacklist
  if (row.nao_contatar === 'TRUE' || row.nao_contatar === true) { continue; }

  // Já recuperado/recusou definitivo -> não dispara
  if (['recuperado', 'pago', 'recusou_final', 'encerrado'].includes((row.status||'').toLowerCase())) { continue; }

  // Dias desde o último contato
  let diasDesdeContato = 999;
  if (row.data_ultimo_contato) {
    const ult = new Date(row.data_ultimo_contato);
    ult.setHours(0,0,0,0);
    diasDesdeContato = Math.floor((hoje - ult) / (1000*60*60*24));
  }

  const faseAtual = (row.fase_pd || '').toUpperCase();
  let faseProxima = null;

  // Cadência de 3 toques: OFERTA (T0) -> LEMBRETE (T+3) -> ULTIMA (T+6)
  if (!faseAtual)                                  faseProxima = 'OFERTA';
  else if (faseAtual === 'OFERTA' && diasDesdeContato >= 3)  faseProxima = 'LEMBRETE';
  else if (faseAtual === 'LEMBRETE' && diasDesdeContato >= 3) faseProxima = 'ULTIMA';
  else continue; // ainda dentro do intervalo ou já no fim da cadência

  elegiveis.push({ ...row, faseProxima });
}

logs.push(`Elegíveis hoje: ${elegiveis.length} | Limite: ${LIMITE_DIA}`);
console.log(logs.join(' | '));

return elegiveis.slice(0, LIMITE_DIA).map(r => ({ json: r }));

// Monta a mensagem do toque correto da campanha de perdão de dívida
const row = $input.first().json;
const nome = (row.nome || 'tudo bem').split(' ')[0];
const aVista = parseFloat(row.valor_a_vista_50 || 0).toFixed(2).replace('.', ',');
const divida = parseFloat(row.valor_divida || 0).toFixed(2).replace('.', ',');
const pix = row.link_pix || 'me chama aqui que te mando o Pix';
const fase = row.faseProxima;

const msgs = {
  OFERTA: `Oi ${nome}! 👋 Aqui é da SST Card. Tenho uma notícia boa pra você: abrimos uma *Campanha de Perdão de Dívida* só até *30/06*.\n\nSua pendência hoje é de R$${divida}. Na campanha você *quita à vista por R$${aVista}* (50% de desconto) e seu cartão de saúde volta a funcionar — telemedicina, auxílio funeral e atendimento com custo reduzido.\n\nQuer aproveitar? Respondo aqui mesmo. 😊`,

  LEMBRETE: `${nome}, passando pra lembrar 🙌 A *Campanha de Perdão de Dívida* da SST Card encerra *30/06*. Você ainda consegue quitar tudo por *R$${aVista} à vista* (metade do valor) e reativar seu cartão na hora.\n\nÉ rápido: ${pix}. Quer que eu já te envie?`,

  ULTIMA: `${nome}, *última chamada*. ⏳ A campanha de 50% encerra dia 30/06 e não vai se repetir esse ano. Depois disso a pendência volta ao valor cheio (R$${divida}).\n\nQuita hoje por *R$${aVista}* e zera tudo. Me responde *SIM* que eu finalizo agora com você.`
};

return [{ json: { ...row, mensagem: msgs[fase] || msgs.OFERTA } }];
